import React from 'react'
import { render, screen, fireEvent, waitFor } from '@testing-library/react'
import { describe, it, expect, beforeEach, afterEach } from '@jest/globals'
import Button from '@/components/ui/Button'

describe('Button Component', () => {
  beforeEach(() => {
    jest.clearAllMocks()
  })

  afterEach(() => {
    jest.restoreAllMocks()
  })

  describe('Rendering', () => {
    it('renders with default props', () => {
      render(<Button>Test Button</Button>)

      const button = screen.getByRole('button', { name: /test button/i })
      expect(button).toBeInTheDocument()
      expect(button).toHaveTextContent('Test Button')
    })

    it('renders with custom className', () => {
      render(<Button className="custom-class">Test</Button>)

      const button = screen.getByRole('button')
      expect(button).toHaveClass('custom-class')
    })

    it('renders with different variants', () => {
      const { rerender } = render(<Button variant="secondary">Secondary</Button>)

      let button = screen.getByRole('button')
      expect(button).toHaveClass('bg-gray-700')

      rerender(<Button variant="danger">Danger</Button>)
      button = screen.getByRole('button')
      expect(button).toHaveClass('bg-red-600')
    })

    it('renders with different sizes', () => {
      const { rerender } = render(<Button size="sm">Small</Button>)

      let button = screen.getByRole('button')
      expect(button).toHaveClass('px-3 py-1.5 text-sm')

      rerender(<Button size="lg">Large</Button>)
      button = screen.getByRole('button')
      expect(button).toHaveClass('px-6 py-3 text-lg')
    })
  })

  describe('Interactions', () => {
    it('handles click events', async () => {
      const handleClick = jest.fn()
      render(<Button onClick={handleClick}>Click me</Button>)

      const button = screen.getByRole('button')
      await fireEvent.click(button)

      expect(handleClick).toHaveBeenCalledTimes(1)
    })

    it('handles disabled state', () => {
      const handleClick = jest.fn()
      render(<Button disabled onClick={handleClick}>Disabled</Button>)

      const button = screen.getByRole('button')
      expect(button).toBeDisabled()

      fireEvent.click(button)
      expect(handleClick).not.toHaveBeenCalled()
    })

    it('handles loading state', () => {
      render(<Button loading>Loading...</Button>)

      const button = screen.getByRole('button')
      expect(button).toBeDisabled()
      expect(button).toHaveAttribute('data-loading', 'true')
    })
  })

  describe('Accessibility', () => {
    it('has proper ARIA attributes', () => {
      render(<Button disabled>Accessible</Button>)

      const button = screen.getByRole('button')
      expect(button).toHaveAttribute('aria-disabled', 'true')
    })

    it('supports keyboard navigation', async () => {
      const handleClick = jest.fn()
      render(<Button onClick={handleClick}>Keyboard</Button>)

      const button = screen.getByRole('button')
      button.focus()

      await fireEvent.keyDown(button, { key: 'Enter' })
      expect(handleClick).toHaveBeenCalledTimes(1)
    })

    it('has proper focus management', () => {
      render(<Button>Focus Test</Button>)

      const button = screen.getByRole('button')

      button.focus()
      expect(button).toHaveFocus()

      button.blur()
      expect(button).not.toHaveFocus()
    })
  })

  describe('Icon Support', () => {
    it('renders with left icon', () => {
      render(<Button icon={<span data-testid="test-icon">­şÜÇ</span>}>With Icon</Button>)

      const icon = screen.getByTestId('test-icon')
      expect(icon).toBeInTheDocument()
      expect(icon).toHaveTextContent('­şÜÇ')
    })

    it('renders with right icon', () => {
      render(<Button icon={<span data-testid="test-icon">ÔÜí</span>} iconPosition="right">Right Icon</Button>)

      const icon = screen.getByTestId('test-icon')
      expect(icon).toBeInTheDocument()
    })
  })

  describe('Form Integration', () => {
    it('works in form context', async () => {
      const handleSubmit = jest.fn()
      render(
        <form onSubmit={handleSubmit}>
          <Button type="submit">Submit</Button>
        </form>
      )

      const button = screen.getByRole('button')
      await fireEvent.click(button)

      expect(handleSubmit).toHaveBeenCalledTimes(1)
    })
  })

  describe('Error Handling', () => {
    it('renders error state', () => {
      render(<Button error>Error Button</Button>)

      const button = screen.getByRole('button')
      expect(button).toHaveClass('border-red-500')
    })

    it('shows error message when provided', () => {
      render(<Button error="Something went wrong">Error</Button>)

      const errorMessage = screen.getByText('Something went wrong')
      expect(errorMessage).toBeInTheDocument()
    })
  })
})

import React from 'react'
import { render, screen, fireEvent, waitFor } from '@testing-library/react'
import { describe, it, expect, beforeEach, afterEach } from '@jest/globals'
import Input from '@/components/ui/Input'

describe('Input Component', () => {
  beforeEach(() => {
    jest.clearAllMocks()
  })

  afterEach(() => {
    jest.restoreAllMocks()
  })

  describe('Rendering', () => {
    it('renders with default props', () => {
      render(<Input placeholder="Test input" />)

      const input = screen.getByPlaceholderText('Test input')
      expect(input).toBeInTheDocument()
      expect(input).toHaveAttribute('type', 'text')
    })

    it('renders with custom type', () => {
      render(<Input type="email" placeholder="Email" />)

      const input = screen.getByPlaceholderText('Email')
      expect(input).toHaveAttribute('type', 'email')
    })

    it('renders with label', () => {
      render(<Input label="Test Label" placeholder="Test" />)

      const label = screen.getByText('Test Label')
      const input = screen.getByPlaceholderText('Test')

      expect(label).toBeInTheDocument()
      expect(input).toBeInTheDocument()
      expect(input).toHaveAttribute('aria-labelledby', expect.any(String))
    })

    it('renders with icon', () => {
      render(<Input icon={<span data-testid="test-icon">­şöı</span>} placeholder="Search" />)

      const icon = screen.getByTestId('test-icon')
      expect(icon).toBeInTheDocument()
    })
  })

  describe('Value Handling', () => {
    it('handles controlled input', async () => {
      const handleChange = jest.fn()
      render(<Input value="initial" onChange={handleChange} />)

      const input = screen.getByDisplayValue('initial')
      expect(input).toBeInTheDocument()

      await fireEvent.change(input, { target: { value: 'new value' } })
      expect(handleChange).toHaveBeenCalledWith(expect.objectContaining({
        target: expect.objectContaining({ value: 'new value' })
      }))
    })

    it('handles uncontrolled input', async () => {
      render(<Input defaultValue="default" />)

      const input = screen.getByDisplayValue('default')
      expect(input).toBeInTheDocument()

      await fireEvent.change(input, { target: { value: 'changed' } })
      expect(input).toHaveDisplayValue('changed')
    })
  })

  describe('Validation', () => {
    it('shows error state', () => {
      render(<Input error="This field is required" />)

      const input = screen.getByRole('textbox')
      expect(input).toHaveClass('border-red-500')
    })

    it('displays error message', () => {
      render(<Input error="Error message" />)

      const errorMessage = screen.getByText('Error message')
      expect(errorMessage).toBeInTheDocument()
    })

    it('applies required attribute', () => {
      render(<Input required />)

      const input = screen.getByRole('textbox')
      expect(input).toBeRequired()
    })
  })

  describe('Accessibility', () => {
    it('has proper ARIA attributes', () => {
      render(<Input aria-label="Custom label" />)

      const input = screen.getByRole('textbox')
      expect(input).toHaveAttribute('aria-label', 'Custom label')
    })

    it('supports keyboard navigation', async () => {
      const handleChange = jest.fn()
      render(<Input onChange={handleChange} />)

      const input = screen.getByRole('textbox')
      input.focus()

      await fireEvent.keyDown(input, { key: 'a' })
      expect(handleChange).toHaveBeenCalled()
    })

    it('has proper focus management', () => {
      render(<Input />)

      const input = screen.getByRole('textbox')

      input.focus()
      expect(input).toHaveFocus()

      input.blur()
      expect(input).not.toHaveFocus()
    })
  })

  describe('Special Features', () => {
    it('handles password type', () => {
      render(<Input type="password" placeholder="Password" />)

      const input = screen.getByPlaceholderText('Password')
      expect(input).toHaveAttribute('type', 'password')
    })

    it('handles textarea type', () => {
      render(<Input type="textarea" placeholder="Message" />)

      const textarea = screen.getByPlaceholderText('Message')
      expect(textarea).toBeInTheDocument()
      expect(textarea.tagName).toBe('TEXTAREA')
    })

    it('handles disabled state', () => {
      render(<Input disabled />)

      const input = screen.getByRole('textbox')
      expect(input).toBeDisabled()
    })

    it('handles maxlength', () => {
      render(<Input maxLength={10} />)

      const input = screen.getByRole('textbox')
      expect(input).toHaveAttribute('maxlength', '10')
    })
  })

  describe('Form Integration', () => {
    it('works within form', async () => {
      const handleSubmit = jest.fn()
      render(
        <form onSubmit={handleSubmit}>
          <Input name="testField" placeholder="Test" />
          <button type="submit">Submit</button>
        </form>
      )

      const input = screen.getByPlaceholderText('Test')
      await fireEvent.change(input, { target: { value: 'test value' } })

      const form = screen.getByRole('form')
      fireEvent.submit(form)

      expect(handleSubmit).toHaveBeenCalledWith(
        expect.objectContaining({
          elements: expect.arrayContaining([
            expect.objectContaining({
              name: 'testField',
              value: 'test value'
            })
          ])
        })
      )
    })
  })
})

import { test, expect } from '@playwright/test'

test.describe('Login Page E2E Tests', () => {
  test.beforeEach(async ({ page }) => {
    await page.goto('/portal/login')
  })

  test('should display login form', async ({ page }) => {
    await expect(page.getByRole('heading', { name: 'Giri┼ş Yap' })).toBeVisible()
    await expect(page.getByLabel('E-posta')).toBeVisible()
    await expect(page.getByLabel('┼Şifre')).toBeVisible()
    await expect(page.getByRole('button', { name: 'Giri┼ş Yap' })).toBeVisible()
  })

  test('should show validation errors for empty form', async ({ page }) => {
    await page.getByRole('button', { name: 'Giri┼ş Yap' }).click()

    await expect(page.getByText('E-posta alan─▒ zorunludur')).toBeVisible()
    await expect(page.getByText('┼Şifre alan─▒ zorunludur')).toBeVisible()
  })

  test('should show error for invalid credentials', async ({ page }) => {
    await page.getByLabel('E-posta').fill('wrong@email.com')
    await page.getByLabel('┼Şifre').fill('wrongpassword')
    await page.getByRole('button', { name: 'Giri┼ş Yap' }).click()

    await expect(page.getByText('Ge├ğersiz kimlik bilgileri')).toBeVisible()
  })

  test('should login successfully with valid credentials', async ({ page }) => {
    await page.getByLabel('E-posta').fill('test@axiar.io')
    await page.getByLabel('┼Şifre').fill('password123')
    await page.getByRole('button', { name: 'Giri┼ş Yap' }).click()

    // Should redirect to dashboard
    await expect(page).toHaveURL('/portal/dashboard')
  })

  test('should navigate to forgot password', async ({ page }) => {
    const forgotLink = page.getByRole('link', { name: '┼Şifremi Unuttum' })
    await expect(forgotLink).toBeVisible()

    await forgotLink.click()
    await expect(page).toHaveURL('/portal/forgot-password')
  })

  test('should handle loading state', async ({ page }) => {
    // Mock slow response
    await page.route('/api/auth/login', route => {
      setTimeout(() => {
        route.fulfill({
          status: 200,
          contentType: 'application/json',
          body: JSON.stringify({
            user: { id: '1', email: 'test@axiar.io' },
            token: 'mock-token'
          })
        })
      }, 2000)
    })

    await page.getByLabel('E-posta').fill('test@axiar.io')
    await page.getByLabel('┼Şifre').fill('password123')
    await page.getByRole('button', { name: 'Giri┼ş Yap' }).click()

    // Should show loading state
    await expect(page.getByRole('button', { name: 'Giri┼ş Yap─▒l─▒yor...' })).toBeVisible()
    await expect(page.getByLabel('E-posta')).toBeDisabled()
    await expect(page.getByLabel('┼Şifre')).toBeDisabled()

    // Should complete after response
    await expect(page.getByRole('button', { name: 'Giri┼ş Yap' })).toBeVisible()
    await expect(page).toHaveURL('/portal/dashboard')
  })

  test('should be accessible via keyboard', async ({ page }) => {
    await page.keyboard.press('Tab')
    await expect(page.getByLabel('E-posta')).toBeFocused()

    await page.keyboard.press('Tab')
    await expect(page.getByLabel('┼Şifre')).toBeFocused()

    await page.keyboard.press('Tab')
    await expect(page.getByRole('button', { name: 'Giri┼ş Yap' })).toBeFocused()

    await page.keyboard.press('Enter')
    await expect(page.getByText('E-posta alan─▒ zorunludur')).toBeVisible()
  })

  test('should have proper meta tags', async ({ page }) => {
    const title = await page.title()
    expect(title).toBe('Giri┼ş Yap | Axiar Intelligence Platform')

    const description = await page.getAttribute('meta[name="description"]', 'content')
    expect(description).toContain('Axiar Intelligence Platform')
  })

  test('should handle responsive design', async ({ page }) => {
    // Test mobile viewport
    await page.setViewportSize({ width: 375, height: 667 })
    await expect(page.getByRole('heading', { name: 'Giri┼ş Yap' })).toBeVisible()

    // Test tablet viewport
    await page.setViewportSize({ width: 768, height: 1024 })
    await expect(page.getByRole('heading', { name: 'Giri┼ş Yap' })).toBeVisible()

    // Test desktop viewport
    await page.setViewportSize({ width: 1920, height: 1080 })
    await expect(page.getByRole('heading', { name: 'Giri┼ş Yap' })).toBeVisible()
  })

  test('should handle network errors gracefully', async ({ page }) => {
    // Mock network error
    await page.route('/api/auth/login', route => {
      route.fulfill({
        status: 500,
        contentType: 'application/json',
        body: JSON.stringify({ error: 'Network error' })
      })
    })

    await page.getByLabel('E-posta').fill('test@axiar.io')
    await page.getByLabel('┼Şifre').fill('password123')
    await page.getByRole('button', { name: 'Giri┼ş Yap' }).click()

    await expect(page.getByText('Ba─şlant─▒ hatas─▒')).toBeVisible()
    await expect(page.getByRole('button', { name: 'Giri┼ş Yap' })).toBeVisible()
  })

  test('should clear errors on input change', async ({ page }) => {
    // First trigger error
    await page.getByRole('button', { name: 'Giri┼ş Yap' }).click()
    await expect(page.getByText('E-posta alan─▒ zorunludur')).toBeVisible()

    // Clear error by typing
    await page.getByLabel('E-posta').fill('test@axiar.io')
    await expect(page.getByText('E-posta alan─▒ zorunludur')).not.toBeVisible()
  })

  test('should have proper loading indicators', async ({ page }) => {
    // Mock loading state
    await page.route('/api/auth/login', route => {
      // Don't fulfill immediately to show loading
    })

    await page.getByLabel('E-posta').fill('test@axiar.io')
    await page.getByLabel('┼Şifre').fill('password123')
    await page.getByRole('button', { name: 'Giri┼ş Yap' }).click()

    // Check for loading attributes
    const button = page.getByRole('button', { name: 'Giri┼ş Yap' })
    await expect(button).toHaveAttribute('data-loading', 'true')
    await expect(button).toBeDisabled()
  })
})

// Contact API endpoint
import { z } from 'zod'

// Form validation schema
const contactSchema = z.object({
  name: z.string().min(2, '─░sim en az 2 karakter olmal─▒').max(50, '─░sim 50 karakterden fazla olamaz'),
  email: z.string().email('Ge├ğerli bir e-posta adresi gerekli'),
  subject: z.string().min(5, 'Konu en az 5 karakter olmal─▒').max(100, 'Konu 100 karakterden fazla olamaz'),
  message: z.string().min(10, 'Mesaj en az 10 karakter olmal─▒').max(1000, 'Mesaj 1000 karakterden fazla olamaz')
})

// Mock database for demo purposes
const submissions = []
let submissionId = 1

export const POST = async (req, res) => {
  try {
    // Validate request body
    const validatedData = contactSchema.parse(req.body)

    // Create submission record
    const submission = {
      id: submissionId++,
      ...validatedData,
      timestamp: new Date().toISOString(),
      ip: req.ip || 'unknown',
      userAgent: req.get('User-Agent') || 'unknown'
    }

    submissions.push(submission)

    // Log submission
    console.log('Contact form submission:', submission)

    // Simulate processing time
    await new Promise(resolve => setTimeout(resolve, 500))

