import React, { useState, useEffect, useCallback, useMemo } from 'react'
import { motion, AnimatePresence } from 'framer-motion'
import { Search, Filter, X, ChevronDown, ChevronUp, Calendar, User, Tag, FileText } from 'lucide-react'
import Input from '@/components/ui/Input'
import Button from '@/components/ui/Button'
import Card from '@/components/ui/Card'
import { useDebounce } from '@/hooks/useDebounce'

const AdvancedSearch = ({ 
  onSearch, 
  onFilterChange, 
  filters = [],
  placeholder = "Ara...",
  className = '',
  showFilters = true,
  showAdvancedOptions = true,
  enableHistory = true,
  enableSuggestions = true,
  enableFacets = true
}) => {
  const [query, setQuery] = useState('')
  const [activeFilters, setActiveFilters] = useState({})
  const [showAdvanced, setShowAdvanced] = useState(false)
  const [searchHistory, setSearchHistory] = useState([])
  const [suggestions, setSuggestions] = useState([])
  const [facets, setFacets] = useState({})
  const [isLoading, setIsLoading] = useState(false)
  const [showSuggestions, setShowSuggestions] = useState(false)

  const debouncedQuery = useDebounce(query, 300)

  // Load search history from localStorage
  useEffect(() => {
    if (enableHistory) {
      const history = localStorage.getItem('searchHistory')
      if (history) {
        setSearchHistory(JSON.parse(history))
      }
    }
  }, [enableHistory])

  // Save search history
  const saveToHistory = useCallback((searchQuery) => {
    if (!enableHistory || !searchQuery.trim()) return

    const newHistory = [searchQuery, ...searchHistory.filter(h => h !== searchQuery)].slice(0, 10)
    setSearchHistory(newHistory)
    localStorage.setItem('searchHistory', JSON.stringify(newHistory))
  }, [searchHistory, enableHistory])

  // Fetch suggestions
  const fetchSuggestions = useCallback(async (searchQuery) => {
    if (!enableSuggestions || searchQuery.length < 2) {
      setSuggestions([])
      return
    }

    try {
      setIsLoading(true)
      const response = await fetch(`/api/search/suggestions?q=${encodeURIComponent(searchQuery)}`)
      const data = await response.json()
      setSuggestions(data.suggestions || [])
    } catch (error) {
      console.error('Failed to fetch suggestions:', error)
      setSuggestions([])
    } finally {
      setIsLoading(false)
    }
  }, [enableSuggestions])

  // Fetch facets
  const fetchFacets = useCallback(async () => {
    if (!enableFacets) return

    try {
      const response = await fetch('/api/search/facets')
      const data = await response.json()
      setFacets(data.facets || {})
    } catch (error) {
      console.error('Failed to fetch facets:', error)
      setFacets({})
    }
  }, [enableFacets])

  // Handle search
  const handleSearch = useCallback((searchQuery, searchFilters = activeFilters) => {
    if (!searchQuery.trim() && Object.keys(searchFilters).length === 0) return

    saveToHistory(searchQuery)
    setShowSuggestions(false)

    onSearch?.({
      query: searchQuery,
      filters: searchFilters,
      timestamp: new Date()
    })
  }, [activeFilters, onSearch, saveToHistory])

  // Handle filter change
  const handleFilterChange = useCallback((filterKey, filterValue) => {
    const newFilters = {
      ...activeFilters,
      [filterKey]: filterValue
    }

    setActiveFilters(newFilters)
    onFilterChange?.(newFilters)
  }, [activeFilters, onFilterChange])

  // Clear filter
  const clearFilter = useCallback((filterKey) => {
    const newFilters = { ...activeFilters }
    delete newFilters[filterKey]

    setActiveFilters(newFilters)
    onFilterChange?.(newFilters)
  }, [activeFilters, onFilterChange])

  // Clear all filters
  const clearAllFilters = useCallback(() => {
    setActiveFilters({})
    onFilterChange?.({})
  }, [onFilterChange])

  // Handle debounced search
  useEffect(() => {
    if (debouncedQuery) {
      fetchSuggestions(debouncedQuery)
      handleSearch(debouncedQuery)
    }
  }, [debouncedQuery, handleSearch, fetchSuggestions])

  // Load facets on mount
  useEffect(() => {
    fetchFacets()
  }, [fetchFacets])

  // Render filter input
  const renderFilterInput = (filter) => {
    const value = activeFilters[filter.key] || ''

    switch (filter.type) {
      case 'text':
        return (
          <Input
            placeholder={filter.placeholder}
            value={value}
            onChange={(e) => handleFilterChange(filter.key, e.target.value)}
            icon={filter.icon}
            className="text-sm"
          />
        )

      case 'select':
        return (
          <select
            value={value}
            onChange={(e) => handleFilterChange(filter.key, e.target.value)}
            className="w-full px-3 py-2 bg-gray-800 border border-gray-700 rounded-lg text-white focus:border-cyan-500 focus:outline-none"
          >
            <option value="">{filter.placeholder}</option>
            {filter.options.map(option => (
              <option key={option.value} value={option.value}>
                {option.label}
              </option>
            ))}
          </select>
        )

      case 'date':
        return (
          <Input
            type="date"
            value={value}
            onChange={(e) => handleFilterChange(filter.key, e.target.value)}
            icon={<Calendar className="w-4 h-4" />}
            className="text-sm"
          />
        )

      case 'multiselect':
        return (
          <div className="space-y-2">
            {filter.options.map(option => (
              <label key={option.value} className="flex items-center space-x-2">
                <input
                  type="checkbox"
                  checked={Array.isArray(value) && value.includes(option.value)}
                  onChange={(e) => {
                    const currentValue = Array.isArray(value) ? value : []
                    const newValue = e.target.checked
                      ? [...currentValue, option.value]
                      : currentValue.filter(v => v !== option.value)
                    handleFilterChange(filter.key, newValue)
                  }}
                  className="rounded border-gray-600 bg-gray-800 text-cyan-500 focus:ring-cyan-500"
                />
                <span className="text-sm text-gray-300">{option.label}</span>
              </label>
            ))}
          </div>
        )

      default:
        return null
    }
  }

  // Render active filter tags
  const renderActiveFilters = () => {
    const activeFilterKeys = Object.keys(activeFilters)
    if (activeFilterKeys.length === 0) return null

    return (
      <div className="flex flex-wrap gap-2 mt-3">
        {activeFilterKeys.map(key => {
          const filter = filters.find(f => f.key === key)
          const value = activeFilters[key]

          if (!filter) return null

          return (
            <motion.div
              key={key}
              initial={{ opacity: 0, scale: 0.8 }}
              animate={{ opacity: 1, scale: 1 }}
              exit={{ opacity: 0, scale: 0.8 }}
              className="inline-flex items-center space-x-2 px-3 py-1 bg-cyan-500/20 text-cyan-400 rounded-full text-sm"
            >
              <span className="truncate max-w-32">
                {filter.label}: {Array.isArray(value) ? value.join(', ') : value}
              </span>
              <button
                onClick={() => clearFilter(key)}
                className="hover:text-cyan-300 transition-colors"
              >
                <X className="w-3 h-3" />
              </button>
            </motion.div>
          )
        })}

        {activeFilterKeys.length > 1 && (
          <Button
            variant="secondary"
            size="sm"
            onClick={clearAllFilters}
            className="text-xs"
          >
            Hepsini Temizle
          </Button>
        )}
      </div>
    )
  }

  // Render search suggestions
  const renderSuggestions = () => {
    if (!showSuggestions || suggestions.length === 0) return null

    return (
      <AnimatePresence>
        <motion.div
          initial={{ opacity: 0, y: -10 }}
          animate={{ opacity: 1, y: 0 }}
          exit={{ opacity: 0, y: -10 }}
          className="absolute top-full left-0 right-0 mt-2 bg-gray-900 border border-gray-700 rounded-lg shadow-xl z-50"
        >
          {suggestions.map((suggestion, index) => (
            <button
              key={index}
              onClick={() => {
                setQuery(suggestion)
                handleSearch(suggestion)
              }}
              className="w-full px-4 py-3 text-left hover:bg-gray-800 transition-colors first:rounded-t-lg last:rounded-b-lg"
            >
              <div className="flex items-center space-x-3">
                <Search className="w-4 h-4 text-gray-400" />
                <span className="text-white">{suggestion}</span>
              </div>
            </button>
          ))}
        </motion.div>
      </AnimatePresence>
    )
  }

  // Render search history
  const renderHistory = () => {
    if (!enableHistory || searchHistory.length === 0) return null

    return (
      <div className="mt-4">
        <h4 className="text-sm font-medium text-gray-400 mb-2">Arama Ge├ğmi┼şi</h4>
        <div className="space-y-1">
          {searchHistory.slice(0, 5).map((historyItem, index) => (
            <button
              key={index}
              onClick={() => {
                setQuery(historyItem)
                handleSearch(historyItem)
              }}
              className="w-full text-left px-3 py-2 text-sm text-gray-400 hover:text-white hover:bg-gray-800 rounded-lg transition-colors"
            >
              <div className="flex items-center space-x-2">
                <Search className="w-3 h-3" />
                <span className="truncate">{historyItem}</span>
              </div>
            </button>
          ))}
        </div>
      </div>
    )
  }

  // Render facets
  const renderFacets = () => {
    if (!enableFacets || Object.keys(facets).length === 0) return null

    return (
      <div className="mt-4 space-y-4">
        {Object.entries(facets).map(([facetKey, facetData]) => (
          <div key={facetKey}>
            <h4 className="text-sm font-medium text-gray-400 mb-2">{facetData.label}</h4>
            <div className="space-y-1">
              {facetData.values.map((value, index) => (
                <button
                  key={index}
                  onClick={() => handleFilterChange(facetKey, value.key)}
                  className="w-full text-left px-3 py-2 text-sm text-gray-400 hover:text-white hover:bg-gray-800 rounded-lg transition-colors flex items-center justify-between"
                >
                  <span>{value.label}</span>
                  <span className="text-xs text-gray-500">({value.count})</span>
                </button>
              ))}
            </div>
          </div>
        ))}
      </div>
    )
  }

  return (
    <Card glass className={`p-6 ${className}`}>
      {/* Search Input */}
      <div className="relative">
        <Input
          placeholder={placeholder}
          value={query}
          onChange={(e) => setQuery(e.target.value)}
          onFocus={() => setShowSuggestions(true)}
          onBlur={() => setTimeout(() => setShowSuggestions(false), 200)}
          icon={<Search className="w-5 h-5" />}
          className="pr-12"
        />

        {/* Search Button */}
        <Button
          onClick={() => handleSearch(query)}
          className="absolute right-2 top-1/2 transform -translate-y-1/2"
          size="sm"
        >
          Ara
        </Button>

        {/* Suggestions Dropdown */}
        {renderSuggestions()}
      </div>

      {/* Active Filters */}
      {renderActiveFilters()}

      {/* Advanced Filters Toggle */}
      {showAdvancedOptions && (
        <div className="mt-4">
          <Button
            variant="secondary"
            onClick={() => setShowAdvanced(!showAdvanced)}
            className="w-full justify-between"
          >
            <span className="flex items-center space-x-2">
              <Filter className="w-4 h-4" />
              <span>Geli┼şmi┼ş Filtreler</span>
            </span>
            {showAdvanced ? <ChevronUp className="w-4 h-4" /> : <ChevronDown className="w-4 h-4" />}
          </Button>
        </div>
      )}

      {/* Advanced Filters */}
      <AnimatePresence>
        {showAdvanced && (
          <motion.div
            initial={{ opacity: 0, height: 0 }}
            animate={{ opacity: 1, height: 'auto' }}
            exit={{ opacity: 0, height: 0 }}
            className="mt-4 space-y-4 overflow-hidden"
          >
            {filters.map(filter => (
              <div key={filter.key} className="space-y-2">
                <label className="text-sm font-medium text-gray-300">
                  {filter.label}
                </label>
                {renderFilterInput(filter)}
              </div>
            ))}
          </motion.div>
        )}
      </AnimatePresence>

      {/* History and Facets */}
      <div className="mt-4 grid grid-cols-1 md:grid-cols-2 gap-4">
        {renderHistory()}
        {renderFacets()}
      </div>

      {/* Loading State */}
      {isLoading && (
        <div className="flex items-center justify-center py-2">
          <div className="w-4 h-4 border-2 border-cyan-500 border-t-transparent rounded-full animate-spin" />
        </div>
      )}
    </Card>
  )
}

export default AdvancedSearch

import React, { useRef, useEffect, useState, useCallback } from 'react'
import { motion } from 'framer-motion'
import { BarChart3, LineChart, PieChart, TrendingUp, TrendingDown, Minus } from 'lucide-react'
import Card from '@/components/ui/Card'

// Chart component using Chart.js
const Chart = ({ 
  type = 'bar',
  data,
  options = {},
  width,
  height = 400,
  className = '',
  showLegend = true,
  showTooltip = true,
  responsive = true,
  maintainAspectRatio = true,
  onClick,
  onHover,
  customColors = ['#06b6d4', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6', '#ec4899']
}) => {
  const canvasRef = useRef(null)
  const chartRef = useRef(null)
  const [isChartReady, setIsChartReady] = useState(false)
  const [chartInstance, setChartInstance] = useState(null)

  // Default chart options
  const defaultOptions = {
    responsive,
    maintainAspectRatio,
    plugins: {
      legend: {
        display: showLegend,
        position: 'top',
        labels: {
          color: '#d1d5db',
          font: {
            size: 12
          }
        }
      },
      tooltip: {
        enabled: showTooltip,
        backgroundColor: 'rgba(17, 24, 39, 0.9)',
        titleColor: '#f9fafb',
        bodyColor: '#d1d5db',
        borderColor: '#374151',
        borderWidth: 1,
        padding: 12,
        displayColors: true,
        callbacks: {
          label: function(context) {
            let label = context.dataset.label || ''
            if (label) {
              label += ': '
            }
            if (context.parsed.y !== null) {
              label += context.parsed.y.toLocaleString()
            }
            return label
          }
        }
      }
    },
    scales: {
      x: {
        grid: {
          color: 'rgba(55, 65, 81, 0.5)',
          borderColor: '#374151'
        },
        ticks: {
          color: '#9ca3af'
        }
      },
      y: {
        grid: {
          color: 'rgba(55, 65, 81, 0.5)',
          borderColor: '#374151'
        },
        ticks: {
          color: '#9ca3af'
        }
      }
    },
    animation: {
      duration: 1000,
      easing: 'easeInOutQuart'
    },
    interaction: {
      intersect: false,
      mode: 'index'
    },
    onClick: onClick,
    onHover: onHover
  }

  // Merge custom colors
  const chartData = {
    ...data,
    datasets: data.datasets?.map((dataset, index) => ({
      ...dataset,
      backgroundColor: dataset.backgroundColor || customColors[index % customColors.length],
      borderColor: dataset.borderColor || customColors[index % customColors.length],
      borderWidth: dataset.borderWidth || 1
    }))
  }

  // Initialize chart
  const initializeChart = useCallback(async () => {
    if (!canvasRef.current || !chartData) return

    try {
      // Dynamically import Chart.js
      const Chart = (await import('chart.js')).default

      // Destroy existing chart
      if (chartInstance) {
        chartInstance.destroy()
      }

      // Create new chart
      const ctx = canvasRef.current.getContext('2d')
      const newChart = new Chart(ctx, {
        type,
        data: chartData,
        options: { ...defaultOptions, ...options }
      })

      setChartInstance(newChart)
      setIsChartReady(true)
    } catch (error) {
      console.error('Failed to initialize chart:', error)
    }
  }, [type, chartData, options, defaultOptions, chartInstance])

  // Update chart when data changes
  useEffect(() => {
    if (chartInstance && chartData) {
      chartInstance.data = chartData
      chartInstance.update('active')
    }
  }, [chartData, chartInstance])

  // Initialize chart on mount
  useEffect(() => {
    initializeChart()

    return () => {
      if (chartInstance) {
        chartInstance.destroy()
      }
    }
  }, [initializeChart, chartInstance])

  // Handle canvas resize
  useEffect(() => {
    const handleResize = () => {
      if (chartInstance) {
        chartInstance.resize()
      }
    }

    window.addEventListener('resize', handleResize)
    return () => window.removeEventListener('resize', handleResize)
  }, [chartInstance])

  // Get chart icon based on type
  const getChartIcon = () => {
    switch (type) {
      case 'bar':
        return <BarChart3 className="w-5 h-5" />
      case 'line':
        return <LineChart className="w-5 h-5" />
      case 'pie':
        return <PieChart className="w-5 h-5" />
      case 'doughnut':
        return <PieChart className="w-5 h-5" />
      default:
        return <BarChart3 className="w-5 h-5" />
    }
  }

  return (
    <Card glass className={`p-6 ${className}`}>
      <div className="flex items-center justify-between mb-4">
        <div className="flex items-center space-x-2">
          {getChartIcon()}
          <h3 className="text-lg font-semibold text-white">
            {data?.title || 'Chart'}
          </h3>
        </div>

        {/* Chart Actions */}
        <div className="flex items-center space-x-2">
          <button
            onClick={() => chartInstance?.resetZoom()}
            className="p-2 text-gray-400 hover:text-white transition-colors"
            title="Reset Zoom"
          >
            <Minus className="w-4 h-4" />
          </button>
        </div>
      </div>

      {/* Loading State */}
      {!isChartReady && (
        <div className="flex items-center justify-center" style={{ height }}>
          <div className="w-8 h-8 border-2 border-cyan-500 border-t-transparent rounded-full animate-spin" />
        </div>
      )}

      {/* Chart Canvas */}
      <div className={`relative ${isChartReady ? 'block' : 'hidden'}`}>
        <canvas
          ref={canvasRef}
          width={width}
          height={height}
          className="max-w-full"
        />
      </div>

      {/* Chart Stats */}
      {chartData?.datasets && chartData.datasets.length > 0 && (
        <div className="mt-4 grid grid-cols-2 md:grid-cols-4 gap-4">
          {chartData.datasets.map((dataset, index) => {
            const values = dataset.data.filter(v => typeof v === 'number')
            const total = values.reduce((sum, val) => sum + val, 0)
            const average = values.length > 0 ? total / values.length : 0
            const max = Math.max(...values)
            const min = Math.min(...values)

            return (
              <motion.div
                key={index}
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ delay: index * 0.1 }}
                className="text-center"
              >
                <div className="text-2xl font-bold text-white">
                  {total.toLocaleString()}
                </div>
                <div className="text-sm text-gray-400">
                  {dataset.label || 'Dataset'}
                </div>
                <div className="text-xs text-gray-500">
                  Avg: {average.toFixed(1)} | Max: {max}
                </div>
              </motion.div>
            )
          })}
        </div>
      )}
    </Card>
  )
}

// Stat Card component
export const StatCard = ({ 
  title, 
  value, 
  change, 
  changeType, 
  icon, 
  color = 'cyan',
  trend = 'up',
  className = '',
  format = 'number',
  subtitle,
  onClick
}) => {
  const getTrendIcon = () => {
    if (trend === 'up') return <TrendingUp className="w-4 h-4" />
    if (trend === 'down') return <TrendingDown className="w-4 h-4" />
    return <Minus className="w-4 h-4" />
  }

  const getTrendColor = () => {
    if (trend === 'up') return 'text-green-400'
    if (trend === 'down') return 'text-red-400'
    return 'text-gray-400'
  }

  const formatValue = (val) => {
    switch (format) {
      case 'currency':
        return new Intl.NumberFormat('tr-TR', {
          style: 'currency',
          currency: 'TRY'
        }).format(val)
      case 'percentage':
        return `${val}%`
      case 'number':
      default:
        return val.toLocaleString()
    }
  }

  const colorClasses = {
    cyan: 'bg-cyan-500/20 text-cyan-400 border-cyan-500/30',
    green: 'bg-green-500/20 text-green-400 border-green-500/30',
    yellow: 'bg-yellow-500/20 text-yellow-400 border-yellow-500/30',
    red: 'bg-red-500/20 text-red-400 border-red-500/30',
    purple: 'bg-purple-500/20 text-purple-400 border-purple-500/30',
    pink: 'bg-pink-500/20 text-pink-400 border-pink-500/30'
  }

  return (
    <motion.div
      whileHover={{ scale: 1.02 }}
      whileTap={{ scale: 0.98 }}
      onClick={onClick}
      className={`bg-gray-800/50 backdrop-blur-sm border ${colorClasses[color]} rounded-lg p-6 cursor-pointer transition-all ${className}`}
    >
      <div className="flex items-center justify-between mb-4">
        <div className={`p-3 rounded-lg ${colorClasses[color]}`}>
          {icon}
        </div>

        {change !== undefined && (
          <div className={`flex items-center space-x-1 ${getTrendColor()}`}>
            {getTrendIcon()}
            <span className="text-sm font-medium">
              {change > 0 ? '+' : ''}{change}%
            </span>
          </div>
        )}
      </div>

      <div className="space-y-1">
        <div className="text-2xl font-bold text-white">
          {formatValue(value)}
        </div>
        <div className="text-sm text-gray-400">
          {title}
        </div>
        {subtitle && (
          <div className="text-xs text-gray-500">
            {subtitle}
          </div>
        )}
      </div>
    </motion.div>
  )
}

