import React, { useState, useEffect, useCallback } from 'react'
import { useAnalytics } from '@/hooks/useAnalytics'

const PerformanceMonitor = ({ children }) => {
  const { trackPerformance, trackError } = useAnalytics()
  const [metrics, setMetrics] = useState({
    fcp: 0, // First Contentful Paint
    lcp: 0, // Largest Contentful Paint
    fid: 0, // First Input Delay
    cls: 0, // Cumulative Layout Shift
    ttfb: 0 // Time to First Byte
  })

  // Measure Core Web Vitals
  useEffect(() => {
    if ('PerformanceObserver' in window) {
      // First Contentful Paint
      const fcpObserver = new PerformanceObserver((list) => {
        const entries = list.getEntries()
        entries.forEach(entry => {
          if (entry.name === 'first-contentful-paint') {
            setMetrics(prev => ({ ...prev, fcp: entry.startTime }))
            trackPerformance('fcp', Math.round(entry.startTime), 'milliseconds')
          }
        })
      })
      fcpObserver.observe({ entryTypes: ['paint'] })

      // Largest Contentful Paint
      const lcpObserver = new PerformanceObserver((list) => {
        const entries = list.getEntries()
        const lastEntry = entries[entries.length - 1]
        if (lastEntry) {
          setMetrics(prev => ({ ...prev, lcp: lastEntry.startTime }))
          trackPerformance('lcp', Math.round(lastEntry.startTime), 'milliseconds')
        }
      })
      lcpObserver.observe({ entryTypes: ['largest-contentful-paint'] })

      // First Input Delay
      const fidObserver = new PerformanceObserver((list) => {
        const entries = list.getEntries()
        entries.forEach(entry => {
          if (entry.name === 'first-input') {
            setMetrics(prev => ({ ...prev, fid: entry.processingStart - entry.startTime }))
            trackPerformance('fid', Math.round(entry.processingStart - entry.startTime), 'milliseconds')
          }
        })
      })
      fidObserver.observe({ entryTypes: ['first-input'] })

      // Cumulative Layout Shift
      let clsValue = 0
      const clsObserver = new PerformanceObserver((list) => {
        const entries = list.getEntries()
        entries.forEach(entry => {
          if (!entry.hadRecentInput) {
            clsValue += entry.value
            setMetrics(prev => ({ ...prev, cls: Math.round(clsValue * 1000) / 1000 }))
          }
        })
      })
      clsObserver.observe({ entryTypes: ['layout-shift'] })

      // Resource timing
      const resourceObserver = new PerformanceObserver((list) => {
        const entries = list.getEntries()
        entries.forEach(entry => {
          if (entry.initiatorType === 'navigation') {
            setMetrics(prev => ({ ...prev, ttfb: entry.responseStart - entry.requestStart }))
            trackPerformance('ttfb', Math.round(entry.responseStart - entry.requestStart), 'milliseconds')
          }
        })
      })
      resourceObserver.observe({ entryTypes: ['navigation'] })

      return () => {
        fcpObserver.disconnect()
        lcpObserver.disconnect()
        fidObserver.disconnect()
        clsObserver.disconnect()
        resourceObserver.disconnect()
      }
    }
  }, [trackPerformance])

  // Monitor memory usage
  useEffect(() => {
    const measureMemory = () => {
      if ('memory' in performance) {
        const memoryInfo = performance.memory
        const memoryUsage = {
          used: Math.round(memoryInfo.usedJSHeapSize / 1048576), // MB
          total: Math.round(memoryInfo.totalJSHeapSize / 1048576), // MB
          limit: Math.round(memoryInfo.jsHeapSizeLimit / 1048576) // MB
        }
        trackPerformance('memory_used', memoryUsage.used, 'MB')
        trackPerformance('memory_total', memoryUsage.total, 'MB')
      }
    }

    const interval = setInterval(measureMemory, 30000) // Every 30 seconds
    return () => clearInterval(interval)
  }, [trackPerformance])

  // Monitor network conditions
  useEffect(() => {
    const measureNetwork = () => {
      if ('connection' in navigator) {
        const connection = navigator.connection
        const networkInfo = {
          effectiveType: connection.effectiveType,
          downlink: connection.downlink,
          rtt: connection.rtt,
          saveData: connection.saveData
        }
        trackPerformance('network_type', networkInfo.effectiveType, 'string')
        trackPerformance('network_downlink', networkInfo.downlink, 'Mbps')
        trackPerformance('network_rtt', networkInfo.rtt, 'milliseconds')
      }
    }

    measureNetwork()
    window.addEventListener('online', measureNetwork)
    window.addEventListener('offline', measureNetwork)

    return () => {
      window.removeEventListener('online', measureNetwork)
      window.removeEventListener('offline', measureNetwork)
    }
  }, [trackPerformance])

  // Error boundary for performance errors
  const handleError = useCallback((error, errorInfo) => {
    trackError('performance_error', error.message, {
      componentStack: errorInfo.componentStack,
      timestamp: Date.now()
    })
  }, [trackError])

  // Performance score calculation
  const calculatePerformanceScore = useCallback(() => {
    const { fcp, lcp, fid, cls } = metrics

    let score = 100

    // FCP scoring (0-1800ms, good: <1000ms)
    if (fcp > 1800) score -= 25
    else if (fcp > 1000) score -= 15

    // LCP scoring (0-2500ms, good: <1200ms)
    if (lcp > 2500) score -= 25
    else if (lcp > 1200) score -= 15

    // FID scoring (0-300ms, good: <100ms)
    if (fid > 300) score -= 25
    else if (fid > 100) score -= 15

    // CLS scoring (0-0.25, good: <0.1)
    if (cls > 0.25) score -= 25
    else if (cls > 0.1) score -= 15

    return Math.max(0, score)
  }, [metrics])

  const performanceScore = calculatePerformanceScore()

  return (
    <>
      {children}

      {/* Performance metrics panel (development only) */}
      {process.env.NODE_ENV === 'development' && (
        <div className="fixed bottom-4 right-4 bg-gray-900 text-white p-4 rounded-lg shadow-xl z-50 text-xs">
          <h3 className="font-bold mb-2">Performance Metrics</h3>
          <div className="space-y-1">
            <div>FCP: {metrics.fcp}ms</div>
            <div>LCP: {metrics.lcp}ms</div>
            <div>FID: {metrics.fid}ms</div>
            <div>CLS: {metrics.cls}</div>
            <div>TTFB: {metrics.ttfb}ms</div>
            <div className="font-bold mt-2">Score: {performanceScore}</div>
          </div>
        </div>
      )}
    </>
  )
}

export default PerformanceMonitor

import React, { useState, useRef, useEffect } from 'react'
import { motion } from 'framer-motion'
import { Eye, EyeOff, Shield, AlertTriangle } from 'lucide-react'
import Input from '@/components/ui/Input'
import { sanitizeInput, isValidEmail, isValidPhone } from '@/utils/security'

const SecureInput = ({ 
  type = 'text',
  label,
  placeholder,
  value,
  onChange,
  onBlur,
  error,
  required = false,
  maxLength = 1000,
  validation,
  sanitize = true,
  showStrength = false,
  showToggle = false,
  className = '',
  ...props 
}) => {
  const [showPassword, setShowPassword] = useState(false)
  const [isValid, setIsValid] = useState(true)
  const [validationMessage, setValidationMessage] = useState('')
  const [isFocused, setIsFocused] = useState(false)
  const inputRef = useRef(null)

  // Handle input change with sanitization
  const handleChange = (e) => {
    let newValue = e.target.value

    // Sanitize input if enabled
    if (sanitize) {
      newValue = sanitizeInput(newValue, {
        allowHTML: false,
        maxLength
      })
    }

    // Call original onChange
    if (onChange) {
      const syntheticEvent = {
        ...e,
        target: {
          ...e.target,
          value: newValue
        }
      }
      onChange(syntheticEvent)
    }
  }

  // Validation on blur
  const handleBlur = (e) => {
    setIsFocused(false)

    let newValue = e.target.value
    if (sanitize) {
      newValue = sanitizeInput(newValue)
    }

    // Built-in validation
    if (type === 'email') {
      const valid = isValidEmail(newValue)
      setIsValid(valid)
      setValidationMessage(valid ? '' : 'Ge├ğerli bir e-posta adresi girin')
    } else if (type === 'tel') {
      const valid = isValidPhone(newValue)
      setIsValid(valid)
      setValidationMessage(valid ? '' : 'Ge├ğerli bir telefon numaras─▒ girin')
    } else if (validation) {
      const result = validation(newValue)
      setIsValid(result.valid)
      setValidationMessage(result.message || '')
    } else {
      setIsValid(true)
      setValidationMessage('')
    }

    if (onBlur) {
      onBlur(e)
    }
  }

  // Password strength calculation
  const getPasswordStrength = () => {
    if (type !== 'password' || !showStrength) return null

    const { checkPasswordStrength } = require('@/utils/security')
    return checkPasswordStrength(value || '')
  }

  const passwordStrength = getPasswordStrength()

  // Get input type
  const getInputType = () => {
    if (type === 'password' && showToggle) {
      return showPassword ? 'text' : 'password'
    }
    return type
  }

  // Get security icon
  const getSecurityIcon = () => {
    if (!isFocused && !error) return null

    if (error) {
      return <AlertTriangle className="w-4 h-4 text-red-400" />
    }

    if (type === 'password' && showStrength && value) {
      const strengthColor = passwordStrength?.strength === 'weak' ? 'text-red-400' :
                          passwordStrength?.strength === 'medium' ? 'text-yellow-400' :
                          passwordStrength?.strength === 'strong' ? 'text-green-400' :
                          'text-green-500'
      return <Shield className={`w-4 h-4 ${strengthColor}`} />
    }

    if (isValid && value) {
      return <Shield className="w-4 h-4 text-green-400" />
    }

    return null
  }

  return (
    <div className={`relative ${className}`}>
      <Input
        ref={inputRef}
        type={getInputType()}
        label={label}
        placeholder={placeholder}
        value={value}
        onChange={handleChange}
        onBlur={handleBlur}
        onFocus={() => setIsFocused(true)}
        maxLength={maxLength}
        required={required}
        error={error || validationMessage}
        icon={getSecurityIcon()}
        className={`${!isValid ? 'border-red-500' : ''} ${type === 'password' && showToggle ? 'pr-12' : ''}`}
        {...props}
      />

      {/* Password toggle */}
      {type === 'password' && showToggle && (
        <button
          type="button"
          onClick={() => setShowPassword(!showPassword)}
          className="absolute right-3 top-1/2 transform -translate-y-1/2 text-gray-400 hover:text-white transition-colors"
          aria-label={showPassword ? '┼Şifreyi gizle' : '┼Şifreyi g├Âster'}
        >
          {showPassword ? (
            <EyeOff className="w-4 h-4" />
          ) : (
            <Eye className="w-4 h-4" />
          )}
        </button>
      )}

      {/* Password strength indicator */}
      {type === 'password' && showStrength && value && (
        <motion.div
          initial={{ opacity: 0, height: 0 }}
          animate={{ opacity: 1, height: 'auto' }}
          className="mt-2"
        >
          <div className="flex items-center justify-between text-xs">
            <span className="text-gray-400">┼Şifre g├╝c├╝:</span>
            <span className={`font-medium ${
              passwordStrength?.strength === 'weak' ? 'text-red-400' :
              passwordStrength?.strength === 'medium' ? 'text-yellow-400' :
              passwordStrength?.strength === 'strong' ? 'text-green-400' :
              'text-green-500'
            }`}>
              {passwordStrength?.strength === 'weak' ? 'Zay─▒f' :
               passwordStrength?.strength === 'medium' ? 'Orta' :
               passwordStrength?.strength === 'strong' ? 'G├╝├ğl├╝' :
               '├çok G├╝├ğl├╝'}
            </span>
          </div>

          {/* Strength bar */}
          <div className="mt-1 h-2 bg-gray-700 rounded-full overflow-hidden">
            <motion.div
              initial={{ width: 0 }}
              animate={{ width: `${(passwordStrength?.score || 0) * 16.67}%` }}
              transition={{ duration: 0.3 }}
              className={`h-full ${
                passwordStrength?.strength === 'weak' ? 'bg-red-500' :
                passwordStrength?.strength === 'medium' ? 'bg-yellow-500' :
                passwordStrength?.strength === 'strong' ? 'bg-green-500' :
                'bg-green-600'
              }`}
            />
          </div>

          {/* Feedback */}
          {passwordStrength?.feedback && passwordStrength.feedback.length > 0 && (
            <div className="mt-2 text-xs text-gray-400">
              {passwordStrength.feedback.join(', ')}
            </div>
          )}
        </motion.div>
      )}
    </div>
  )
}

