                      </Button>
                      <Button
                        variant="secondary"
                        onClick={() => handleRejectTask(selectedTask.id, 'Kullan─▒c─▒ taraf─▒ndan reddedildi')}
                        className="flex-1"
                      >
                        <XCircle className="w-4 h-4 mr-2" />
                        Reddet
                      </Button>
                    </>
                  )}
                </div>
              </div>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  )
}

