                  </div>
                  <div className="w-24">
                    <div className="text-sm text-gray-400">Confidence</div>
                    <div className="text-white">{period.confidence}%</div>
                  </div>
                </motion.div>
              ))}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

