import { useState, useEffect, useCallback } from 'react'

export const useDebounce = (value, delay) => {
  const [debouncedValue, setDebouncedValue] = useState(value)

  useEffect(() => {
    const handler = setTimeout(() => {
      setDebouncedValue(value)
    }, delay)

    return () => {
      clearTimeout(handler)
    }
  }, [value, delay])

  return debouncedValue
}

export const useDebouncedCallback = (callback, delay) => {
  const [debouncedCallback, setDebouncedCallback] = useState(null)

  useEffect(() => {
    const handler = setTimeout(() => {
      setDebouncedCallback(() => callback)
    }, delay)

    return () => {
      clearTimeout(handler)
    }
  }, [callback, delay])

  return debouncedCallback
}

export const useThrottle = (value, limit) => {
  const [throttledValue, setThrottledValue] = useState(value)
  const lastRan = useRef(Date.now())

  useEffect(() => {
    const handler = setTimeout(() => {
      if (Date.now() - lastRan.current >= limit) {
        callback(value)
        lastRan.current = Date.now()
      }
    }, limit - (Date.now() - lastRan.current))

    return () => {
      clearTimeout(handler)
    }
  }, [value, limit])

  const callback = useCallback((valueToSet) => {
    setThrottledValue(valueToSet)
  }, [])

  return throttledValue
}

// Utility debounce function
export const debounce = (func, wait) => {
  let timeout
  return function executedFunction(...args) {
    const later = () => {
      clearTimeout(timeout)
      func(...args)
    }
    clearTimeout(timeout)
    timeout = setTimeout(later, wait)
  }
}

// Utility throttle function
export const throttle = (func, limit) => {
  let inThrottle
  return function() {
    const args = arguments
    const context = this
    if (!inThrottle) {
      func.apply(context, args)
      inThrottle = true
      setTimeout(() => inThrottle = false, limit)
    }
  }
}

import { useState, useEffect, useCallback, useRef } from 'react'

export const useIntersection = (options = {}) => {
  const [isIntersecting, setIsIntersecting] = useState(false)
  const [entry, setEntry] = useState(null)
  const ref = useRef(null)

  const {
    threshold = 0.1,
    root = null,
    rootMargin = '0px',
    triggerOnce = false,
    enabled = true
  } = options

  useEffect(() => {
    if (!enabled) return

    const element = ref.current
    if (!element) return

    const observer = new IntersectionObserver(
      ([entry]) => {
        setIsIntersecting(entry.isIntersecting)
        setEntry(entry)

        if (entry.isIntersecting && triggerOnce) {
          observer.unobserve(element)
        }
      },
      {
        threshold,
        root,
        rootMargin
      }
    )

    observer.observe(element)

    return () => {
      observer.unobserve(element)
    }
  }, [threshold, root, rootMargin, triggerOnce, enabled])

  return {
    ref,
    isIntersecting,
    entry
  }
}

export const useIntersectionObserver = (elements, options = {}) => {
  const [entries, setEntries] = useState([])
  const observerRef = useRef(null)

  const {
    threshold = 0.1,
    root = null,
    rootMargin = '0px'
  } = options

  useEffect(() => {
    if (!elements || elements.length === 0) return

    observerRef.current = new IntersectionObserver(
      (entries) => {
        setEntries(entries)
      },
      {
        threshold,
        root,
        rootMargin
      }
    )

    elements.forEach(element => {
      if (element) {
        observerRef.current.observe(element)
      }
    })

    return () => {
      if (observerRef.current) {
        observerRef.current.disconnect()
      }
    }
  }, [elements, threshold, root, rootMargin])

  return {
    entries,
    disconnect: () => {
      if (observerRef.current) {
        observerRef.current.disconnect()
      }
    }
  }
}

import { useState, useEffect, useCallback } from 'react'

export const useLoading = (initialState = false) => {
  const [isLoading, setIsLoading] = useState(initialState)
  const [loadingMessage, setLoadingMessage] = useState('')

  const startLoading = useCallback((message = '') => {
    setIsLoading(true)
    setLoadingMessage(message)
  }, [])

  const stopLoading = useCallback(() => {
    setIsLoading(false)
    setLoadingMessage('')
  }, [])

  const toggleLoading = useCallback(() => {
    setIsLoading(prev => !prev)
    if (!isLoading) {
      setLoadingMessage('')
    }
  }, [isLoading])

  return {
    isLoading,
    loadingMessage,
    startLoading,
    stopLoading,
    toggleLoading,
    setIsLoading
  }
}

export const useAsyncLoading = () => {
  const [operations, setOperations] = useState(new Map())

  const startOperation = useCallback((key, message = '') => {
    setOperations(prev => new Map(prev).set(key, { loading: true, message }))
  }, [])

  const stopOperation = useCallback((key) => {
    setOperations(prev => {
      const newMap = new Map(prev)
      newMap.delete(key)
      return newMap
    })
  }, [])

  const isOperationLoading = useCallback((key) => {
    return operations.get(key)?.loading || false
  }, [operations])

  const getOperationMessage = useCallback((key) => {
    return operations.get(key)?.message || ''
  }, [operations])

  const clearAllOperations = useCallback(() => {
    setOperations(new Map())
  }, [])

  return {
    startOperation,
    stopOperation,
    isOperationLoading,
    getOperationMessage,
    clearAllOperations,
    loadingCount: operations.size
  }
}

import { useState, useEffect, useRef, useMemo } from 'react'

export const useVirtualList = ({
  items,
  itemHeight = 50,
  containerHeight = 400,
  overscan = 5,
  getItemKey = (item, index) => index
}) => {
  const [scrollTop, setScrollTop] = useState(0)
  const containerRef = useRef(null)

  const visibleRange = useMemo(() => {
    const startIndex = Math.max(0, Math.floor(scrollTop / itemHeight) - overscan)
    const endIndex = Math.min(
      items.length - 1,
      Math.ceil((scrollTop + containerHeight) / itemHeight) + overscan
    )

    return { startIndex, endIndex }
  }, [scrollTop, itemHeight, containerHeight, overscan, items.length])

  const visibleItems = useMemo(() => {
    return items.slice(visibleRange.startIndex, visibleRange.endIndex + 1).map((item, index) => ({
      item,
      index: visibleRange.startIndex + index,
      key: getItemKey(item, visibleRange.startIndex + index)
    }))
  }, [items, visibleRange, getItemKey])

  const totalHeight = items.length * itemHeight

  const handleScroll = (e) => {
    setScrollTop(e.target.scrollTop)
  }

  useEffect(() => {
    const container = containerRef.current
    if (container) {
      container.addEventListener('scroll', handleScroll, { passive: true })
      return () => container.removeEventListener('scroll', handleScroll)
    }
  }, [])

  return {
    containerRef,
    visibleItems,
    totalHeight,
    itemHeight,
    containerHeight
  }
}

export const useVirtualGrid = ({
  items,
  itemWidth = 200,
  itemHeight = 200,
  containerWidth = 800,
  containerHeight = 600,
  gap = 16,
  overscan = 2,
  getItemKey = (item, index) => index
}) => {
  const [scrollTop, setScrollTop] = useState(0)
  const [scrollLeft, setScrollLeft] = useState(0)
  const containerRef = useRef(null)

  const columns = useMemo(() => {
    return Math.floor((containerWidth + gap) / (itemWidth + gap))
  }, [containerWidth, itemWidth, gap])

  const visibleRange = useMemo(() => {
    const startRow = Math.max(0, Math.floor(scrollTop / (itemHeight + gap)) - overscan)
    const endRow = Math.min(
      Math.ceil(items.length / columns) - 1,
      Math.ceil((scrollTop + containerHeight) / (itemHeight + gap)) + overscan
    )

    const startIndex = startRow * columns
    const endIndex = Math.min(items.length - 1, (endRow + 1) * columns - 1)

    return { startIndex, endIndex }
  }, [scrollTop, itemHeight, gap, containerHeight, columns, items.length, overscan])

  const visibleItems = useMemo(() => {
    return items.slice(visibleRange.startIndex, visibleRange.endIndex + 1).map((item, index) => {
      const itemIndex = visibleRange.startIndex + index
      const row = Math.floor(itemIndex / columns)
      const col = itemIndex % columns

      return {
        item,
        index: itemIndex,
        key: getItemKey(item, itemIndex),
        row,
        col,
        style: {
          position: 'absolute',
          left: col * (itemWidth + gap),
          top: row * (itemHeight + gap),
          width: itemWidth,
          height: itemHeight
        }
      }
    })
  }, [items, visibleRange, getItemKey, columns, itemWidth, itemHeight, gap])

  const totalRows = Math.ceil(items.length / columns)
  const totalHeight = totalRows * (itemHeight + gap) - gap

  const handleScroll = (e) => {
    setScrollTop(e.target.scrollTop)
    setScrollLeft(e.target.scrollLeft)
  }

  useEffect(() => {
    const container = containerRef.current
    if (container) {
      container.addEventListener('scroll', handleScroll, { passive: true })
      return () => container.removeEventListener('scroll', handleScroll)
    }
  }, [])

  return {
    containerRef,
    visibleItems,
    totalHeight,
    totalRows,
    columns,
    itemWidth,
    itemHeight,
    containerWidth,
    containerHeight
  }
}

